// ── !bloquearfrase ───────────────────────────────────────────────
      if (comando === "!bloquearfrase" && autorizado) {
        const frase = args.join(" ").trim().toLowerCase();
        if (!frase) {
          await sock.sendMessage(from, { text: "❌ Informe a frase: !bloquearfrase [palavra]" });
          continue;
        }
        if (!db.bloqueioFrases.includes(frase)) {
          db.bloqueioFrases.push(frase);
          saveDB(db);
          await sock.sendMessage(from, { text: `✅ A frase "${frase}" foi bloqueada!\n\n_Variações como leetspeak (p0rr@, porr4, etc.) também serão bloqueadas automaticamente._` });
        } else {
          await sock.sendMessage(from, { text: `⚠️ A frase "${frase}" já estava bloqueada.` });
        }
      }

      // ── !desbloquearfrase ────────────────────────────────────────────
      if (comando === "!desbloquearfrase" && autorizado) {
        const frase = args.join(" ").trim().toLowerCase();
        if (!frase) {
          await sock.sendMessage(from, { text: "❌ Informe a frase: !desbloquearfrase [palavra]" });
          continue;
        }
        if (db.bloqueioFrases.includes(frase)) {
          db.bloqueioFrases = db.bloqueioFrases.filter(f => f !== frase);
          saveDB(db);
          await sock.sendMessage(from, { text: `✅ A frase "${frase}" foi desbloqueada!` });
        } else {
          await sock.sendMessage(from, { text: `⚠️ A frase "${frase}" não estava bloqueada.` });
        }
      }

      // ── !listarfrases ────────────────────────────────────────────────
      if (comando === "!listarfrases" && autorizado) {
        if (db.bloqueioFrases.length === 0) {
          await sock.sendMessage(from, { text: "📋 Nenhuma frase bloqueada." });
        } else {
          await sock.sendMessage(from, {
            text: `📋 *Frases bloqueadas:*\n${db.bloqueioFrases.map(f => `• ${f}`).join("\n")}`
          });
        }
      }

      // ── !bloquearaudio ───────────────────────────────────────────────
      if (comando === "!bloquearaudio" && autorizado) {
        db.bloqueioAudios = true;
        saveDB(db);
        await sock.sendMessage(from, { text: "🔇 Áudios bloqueados neste grupo!" });
      }

      // ── !desbloquearaudio ────────────────────────────────────────────
      if (comando === "!desbloquearaudio" && autorizado) {
        db.bloqueioAudios = false;
        saveDB(db);
        await sock.sendMessage(from, { text: "✅ Áudios liberados neste grupo!" });
      }

      // ── !bloquearlink ────────────────────────────────────────────────
      if (comando === "!bloquearlink" && autorizado) {
        db.linksBloqueados = true;
        saveDB(db);
        await sock.sendMessage(from, { text: "🔗 Links bloqueados neste grupo!" });
      }

      // ── !desbloquearlink ─────────────────────────────────────────────
      if (comando === "!desbloquearlink" && autorizado) {
        db.linksBloqueados = false;
        saveDB(db);
        await sock.sendMessage(from, { text: "✅ Links liberados neste grupo!" });
      }

      // ── !apagar ──────────────────────────────────────────────────────
      if (comando === "!apagar" && autorizado) {
        const quoted = msg.message?.extendedTextMessage?.contextInfo?.quotedMessage;
        const quotedKey = msg.message?.extendedTextMessage?.contextInfo?.stanzaId;
        const quotedParticipant = msg.message?.extendedTextMessage?.contextInfo?.participant;
        if (quoted && quotedKey) {
          await sock.sendMessage(from, {
            delete: {
              remoteJid: from,
              fromMe: false,
              id: quotedKey,
              participant: quotedParticipant
            }
          });
        } else {
          await sock.sendMessage(from, { text: "❌ Responda a uma mensagem para apagá-la." });
        }
      }

      // ── !limparavisos ────────────────────────────────────────────────
      if (comando === "!limparavisos" && autorizado) {
        const mencionados = msg.message?.extendedTextMessage?.contextInfo?.mentionedJid || [];
        const alvo = mencionados[0] || toJID(args[0]);
        if (!alvo) {
          await sock.sendMessage(from, { text: "❌ Mencione ou informe o número." });
          continue;
        }
        delete db.avisosBloqueio[alvo];
        saveDB(db);
        await sock.sendMessage(from, {
          text: `✅ Avisos de @${alvo.split("@")[0]} foram limpos!`,
          mentions: [alvo]
        });
      }
    }
  });
}

